// // This module implements a 6-bit wide, 2-to-1 demultiplexer. When the select input is LOW (0), the output will be equal to in1; when the select input is HIGH (1), the output will be equal to in0.
module top_module(in0, in1, select, out);parameter WIDTH = 6;   		
  input [WIDTH - 1:0] in1;      
  input [WIDTH - 1:0] in0;		
  input select;
  output [WIDTH - 1:0] out;

  assign out = select ? in1 : in0;   
endmodule
